def parse_startup_nodes(nodes: str) -> List[Dict[str, Any]]:
    startup_nodes = []
    for raw in nodes.split(","):
        raw = raw.strip()
        if not raw:
            continue
        if ":" not in raw:
            raise ValueError(f"Invalid Redis node format: {raw}. Expected host:port")
        host, port = raw.rsplit(":", 1)
        startup_nodes.append({"host": host.strip(), "port": int(port.strip())})
    if not startup_nodes:
        raise ValueError("No Redis cluster nodes configured")
    return startup_nodes


class RedisCacheService:
    def __init__(self) -> None:
        self.client = self._build_client()

    def _build_client(self) -> RedisCluster:
        startup_nodes = parse_startup_nodes(Config.REDIS_CLUSTER_NODES)
        client = RedisCluster(
            startup_nodes=startup_nodes,
            username=Config.REDIS_USERNAME,
            password=Config.REDIS_PASSWORD,
            ssl=Config.REDIS_SSL,
            decode_responses=Config.REDIS_DECODE_RESPONSES,
            socket_timeout=Config.REDIS_SOCKET_TIMEOUT,
            socket_connect_timeout=Config.REDIS_SOCKET_CONNECT_TIMEOUT,
            health_check_interval=Config.REDIS_HEALTH_CHECK_INTERVAL,
            max_connections=Config.REDIS_MAX_CONNECTIONS,
            retry_on_timeout=Config.REDIS_RETRY_ON_TIMEOUT,
            skip_full_coverage_check=Config.REDIS_SKIP_FULL_COVERAGE_CHECK,
        )
        client.ping()
        logger.info("Connected to Redis cluster")
        return client

    def health(self) -> Dict[str, Any]:
        started = time.time()
        self.client.ping()
        return {
            "status": "ok",
            "redis": "up",
            "latency_ms": round((time.time() - started) * 1000, 2),
        }

    @staticmethod
    def _encode_payload(data: Dict[str, Any]) -> str:
        raw = json.dumps(data, separators=(",", ":"), ensure_ascii=False).encode("utf-8")
        return base64.b64encode(raw).decode("ascii")

    @staticmethod
    def _decode_payload(payload: Optional[str]) -> Optional[Dict[str, Any]]:
        if payload is None:
            return None
        raw = base64.b64decode(payload.encode("ascii"))
        return json.loads(raw.decode("utf-8"))

    def set_value(self, key: str, value: Dict[str, Any], ttl_seconds: int) -> bool:
        payload = self._encode_payload(value)
        return bool(self.client.set(name=key, value=payload, ex=ttl_seconds))

    def get_value(self, key: str) -> Optional[Dict[str, Any]]:
        payload = self.client.get(key)
        return self._decode_payload(payload)

    def delete_value(self, key: str) -> int:
        return int(self.client.delete(key))

    def ttl(self, key: str) -> int:
        return int(self.client.ttl(key))


