@app.post("/cache/session")
def set_session():
    body = request.get_json(silent=True) or {}
    session_id = body.get("session_id")
    session_token = body.get("session_token")
    user_id = body.get("user_id")
    ttl_seconds = int(body.get("ttl_seconds", Config.SESSION_TTL_SECONDS))

    if not session_id or not session_token or not user_id:
        return jsonify({"error": "session_id, session_token, and user_id are required"}), 400
    if ttl_seconds <= 0:
        return jsonify({"error": "ttl_seconds must be greater than 0"}), 400

    key = f"session:{session_id}"
    value = {
        "session_token": session_token,
        "user_id": user_id,
        "created_at": int(time.time()),
        "type": "session",
    }
    cache.set_value(key, value, ttl_seconds)
    return jsonify({"status": "stored", "key": key, "ttl_seconds": ttl_seconds}), 201


@app.get("/cache/session/<session_id>")
def get_session(session_id: str):
    key = f"session:{session_id}"
    value = cache.get_value(key)
    if value is None:
        return jsonify({"error": "not_found"}), 404
    return jsonify({"key": key, "ttl_seconds": cache.ttl(key), "value": value}), 200


@app.delete("/cache/session/<session_id>")
def delete_session(session_id: str):
    key = f"session:{session_id}"
    deleted = cache.delete_value(key)
    if deleted == 0:
        return jsonify({"error": "not_found"}), 404
    return jsonify({"status": "deleted", "key": key}), 200


